INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-12-12T13:26:55.656189+00:00', true, false, false, '019bb25e-e60c-7352-9b81-f411f56092a9', 'Student', 'Represents a typical student perspective, asking questions and seeking clarification on course material and policies.', 'GraduationCap', '#3b82f6', '{}', '', '{"Can you explain this concept again?","I''m not sure I understand the assignment requirements","What should I focus on for the exam?"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-12-12T13:26:55.656189+00:00', true, false, false, '019bb25e-e60c-7356-93ee-b176f32f08cf', 'Professor', 'Represents a faculty member perspective, providing guidance on academic policies and course expectations.', 'User', '#8b5cf6', '{}', '', '{"Let me clarify the course policy on this matter","Based on the syllabus, here''s what you need to know","I want to ensure you understand the academic integrity expectations"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-12-12T13:26:55.656189+00:00', true, false, false, '019bb25e-e60c-7359-9409-c72170bf358e', 'Instructional Staff', 'Represents teaching assistants and instructional support staff, helping students navigate course logistics and policies.', 'Users', '#10b981', '{}', '', '{"I can help you understand how to submit your assignment","Let me walk you through the grading policy","Here''s what you need to know about office hours"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-12-14T19:07:45.268865+00:00', 'FERPA Training Problem Statement', 'An instructional staff member accidentally leaves a student''s grade sheet visible on their computer screen. A student notices the visible information and questions whether this violates FERPA. The staff member must quickly address the situation and explain the importance of protecting student privacy.', '019b3be4-36ec-74e7-b543-ff2dcc3b946c', true, false, false) ON CONFLICT (id) DO NOTHING;
